async fn proxy_handler(
    req: ServiceRequest,
    query_params: web::Query<HashMap<String, String>>
) -> Result<HttpResponse, Error> {
    let target_url = match query_params.get("url") {
        Some(url) => url,
        None => return Ok(HttpResponse::BadRequest().body("Missing 'url' query parameter")),
    };

    // Validate URL
    let parsed_url = match Url::parse(target_url) {
        Ok(url) => url,
        Err(_) => return Ok(HttpResponse::BadRequest().body("Invalid URL")),
    };

    // Whitelist validation - only allow specific domains
    let allowed_domains = ["api.example.com", "api2.example.com"];
    if !allowed_domains.contains(&parsed_url.domain().unwrap_or("")) {
        return Ok(HttpResponse::Forbidden().body("Domain not allowed"));
    }

    // Build client with security settings
    let client = reqwest::Client::builder()
        .timeout(std::time::Duration::from_secs(30))
        .user_agent("Webhook-Proxy/1.0")
        .build()
        .map_err(|_| actix_web::error::ErrorInternalServerError("Failed to build client"))?;

    // Forward request
    let response = client
        .get(target_url)
        .send()
        .await
        .map_err(|_| actix_web::error::ErrorInternalServerError("Failed to fetch"))?;

    let status = response.status();
    let headers = response.headers().clone();
    let body = response.bytes().await.map_err(|_| {
        actix_web::error::ErrorInternalServerError("Failed to read response body")
    })?;

    let mut resp = HttpResponse::build(status);
    
    // Copy headers
    for (key, value) in headers.iter() {
        if key != header::CONTENT_LENGTH && key != header::TRANSFER_ENCODING {
            resp.insert_header((key.clone(), value.clone()));
        }
    }

    Ok(resp.body(body))
}